#!/usr/bin/env -S npx ts-node -r tsconfig-paths/register
/**
 * Example: Google Cloud Platform Default Application Credentials
 *
 * Description: Use GCP default application credentials. Best for applications
 * running in GCP or local development with gcloud CLI.
 *
 * Prerequisites:
 * - Google Cloud SDK installed (for local development)
 * - Authenticated with gcloud CLI OR running in GCP environment
 * - Databricks workspace on GCP
 *
 * Setup (local development):
 * ```bash
 * gcloud auth application-default login
 * ```
 *
 * Setup (GCP environment):
 * - Ensure the service account has permissions to Databricks workspace
 *
 * Run:
 * ```bash
 * DATABRICKS_HOST="https://your-workspace.gcp.databricks.com" \
 * npx ts-node examples/auth/google-default-credentials.ts
 * ```
 */

import {Config, WorkspaceClient} from "@databricks/sdk-experimental";

async function main() {
    const config = new Config({
        host: process.env.DATABRICKS_HOST,
        authType: "google-credentials",
    });

    const client = new WorkspaceClient(config);

    try {
        const user = await client.currentUser.me();
        console.log(
            `✓ Successfully authenticated via GCP default credentials as: ${user.userName}`
        );
        console.log(`  User ID: ${user.id}`);

        console.log(`  Host: ${config.host}`);
    } catch (error) {
        console.error("✗ Authentication failed:", error);
        console.error("\nMake sure you have:");
        console.error("  1. Set DATABRICKS_HOST environment variable");
        console.error("  2. Run: gcloud auth application-default login");
        console.error("  OR running in GCP with service account permissions");
        process.exit(1);
    }
}

main().catch(console.error);
